// Combine all Apollo results and tag by team member
const angelaPeople = $('Apollo - Angela (Strategic Regulatory)').item.json.people || [];
const samPeople = $('Apollo - Sam (Digital Health/AI)').item.json.people || [];
const catrionaPeople = $('Apollo - Catriona (Quality/QMSR)').item.json.people || [];
const jasminePeople = $('Apollo - Jasmine (Strategic Partnerships)').item.json.people || [];
const jeanninePeople = $('Apollo - Jeannine (Business Development)').item.json.people || [];

const allLeads = [];

angelaPeople.forEach((person, i) => {
  allLeads.push({ json: { ...person, teamMember: 'Angela', campaign: 'Strategic Regulatory', leadId: 'AV-A-' + Date.now() + '-' + i }});
});

samPeople.forEach((person, i) => {
  allLeads.push({ json: { ...person, teamMember: 'Sam', campaign: 'AI/ML Devices', leadId: 'AV-S-' + Date.now() + '-' + i }});
});

catrionaPeople.forEach((person, i) => {
  allLeads.push({ json: { ...person, teamMember: 'Catriona', campaign: 'QMSR Compliance', leadId: 'AV-C-' + Date.now() + '-' + i }});
});

jasminePeople.forEach((person, i) => {
  allLeads.push({ json: { ...person, teamMember: 'Jasmine', campaign: 'Strategic Partnerships', leadId: 'AV-J-' + Date.now() + '-' + i }});
});

jeanninePeople.forEach((person, i) => {
  allLeads.push({ json: { ...person, teamMember: 'Jeannine', campaign: 'Full-Service CRO', leadId: 'AV-BD-' + Date.now() + '-' + i }});
});

// Remove duplicates by email
const seen = new Set();
const unique = allLeads.filter(item => {
  const email = item.json.email;
  if (seen.has(email)) return false;
  seen.add(email);
  return true;
});

return unique;

