const content = $json.message?.content || $json.content || '';
const person = $json;

return [{
  json: {
    email: person.email || '',
    firstName: person.first_name || '',
    lastName: person.last_name || '',
    company: person.organization?.name || '',
    title: person.title || '',
    companySize: person.organization?.estimated_num_employees || '',
    location: (person.city || '') + ', ' + (person.state || ''),
    website: person.organization?.website_url || '',
    linkedinUrl: person.linkedin_url || '',
    industry: 'Medical Devices',
    teamMember: person.teamMember || 'Catriona',
    campaign: person.campaign || 'QMSR',
    status: 'Ready',
    leadId: person.leadId || ('AV-' + Date.now()),
    personalizedOpening: content.trim()
  }
}];
